select id, convoke_time, address, compere_id, join_id, people_id, title, contents, createtime, updatetime, unit_id,unit_name,compere_ren,people_ji_lu,file_url,meeting_form
from bdgl_even e left join sys_dept t
on d.unit_id=t.dept_id

     and e.convoke_time = #{convokeTime}
     and e.address = #{address}
     and e.compere_id = #{compereId}
     and e.join_id = #{joinId}
     and e.people_id = #{peopleId}
     and e.title = #{title}
     and e.contents = #{contents}
     and e.createtime = #{createtime}
     and e.updatetime = #{updatetime}
     and e.compere_ren concat('%',#{compereRen}, '%')
     and e.people_ji_lu concat('%', #{peopleJiLu}, '%')
     and e.file_url concat('%', #{fileUrl}, '%')
     and e.meeting_form concat('%', #{meetingForm}, '%')
    and(d.unit_id=#{unitId} or find_in_set(#{unitId}, t.ancestors))

order by e.id desc

select e.id, e.convoke_time, e.address, e.compere_id, e.join_id, e.people_id, e.title, e.contents, e.createtime, e.updatetime, e.unit_id ,e.compere_ren,e.people_ji_lu,e.file_url,e.meeting_form,d.dept_name unit_name   from
bdgl_even e LEFT JOIN sys_dept d ON e.unit_id = d.dept_id


        and (e.unit_id=#{unitId} or find_in_set(#{unitId}, d.ancestors))

     and e.convoke_time = #{convokeTime}
     and e.address = #{address}
     and e.compere_id = #{compereId}
     and e.join_id = #{joinId}
     and e. people_id = #{peopleId}
     and e.title = #{title}
     and e.contents = #{contents}
     and e.createtime = #{createtime}
     and e.updatetime = #{updatetime}
     and e.compere_ren = #{compereRen}
     and e.people_ji_lu = #{peopleJiLu}
     and e.file_url = #{fileUrl}
     and e.meeting_form = #{meetingForm}
     and e.unit_name LIKE  concat('%', #{unitName}, '%')


order by e.id desc

select id, convoke_time, address, compere_id, join_id, people_id, title, contents, createtime, updatetime, unit_id,unit_name,compere_ren,people_ji_lu,file_url,meeting_form
from bdgl_even

     and unit_id = #{unitId}
     and YEAR(convoke_time)= #{year}

order by id desc

